  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});
```

**Recommendation:** Add authentication middleware (e.g., JWT or session check) to all routes that return user data, and enforce authorization so users can only access their own records:

```js
const authenticate = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    res.status(401).json({ error: 'Invalid token' });
  }
};

app.get('/users/:id', authenticate, (req, res) => {
  // Only allow a user to fetch their own record unless they're an admin
  if (req.user.id !== parseInt(req.params.id) && !req.user.isAdmin) {
    return res.status(403).json({ error: 'Forbidden' });
  }
  // ...fetch and return user
});
```

