app.use(helmet());
// Sets: X-Frame-Options, X-Content-Type-Options, Strict-Transport-Security,
//       Content-Security-Policy, X-Permitted-Cross-Domain-Policies, and more.
```

Also explicitly disable the `X-Powered-By` header even without Helmet:
```js
