app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

---

#### 5. No Input Validation (OWASP A03)
No query parameters, path parameters, or request bodies are validated anywhere. When database queries are added, this becomes a direct SQL/NoSQL injection vector.

**Fix:** Integrate a validation library at the route level. Example with `zod`:

```js
const { z } = require('zod');

const UserQuerySchema = z.object({
  page:  z.coerce.number().int().positive().default(1),
  limit: z.coerce.number().int().min(1).max(100).default(20),
});

app.get('/users', requireAuth, (req, res) => {
