  res.json([{ id: 1, name: 'Alice', email: 'alice@example.com' }, ...]);
});
```

**Fix:** Add an authentication middleware (JWT is shown; adapt to your auth system):

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader?.startsWith('Bearer ') ? authHeader.slice(7) : null;

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

// ✅ Protected route
app.get('/users', requireAuth, (req, res) => {
  res.json([...]);
});
```

---

### 🔴 2. Secrets Committed to Repository — Cryptographic/Secrets Failures (A02)

**Problem:** The `.env.test` file in this project contains credentials (database passwords, cloud provider keys, API keys, payment keys). Committing any secrets file to source control — even "test" credentials — is dangerous because:
- Git history is permanent; a `git rm` alone does not scrub secrets.
- "Test" credentials are often reused or rotated to production.
- Canary tokens can be triggered by automated scanners.

**Fix:**

```bash
# 1. Add to .gitignore immediately
echo ".env*" >> .gitignore
echo "!.env.example" >> .gitignore

# 2. If already committed, scrub git history (requires force-push)
git filter-repo --path .env.test --invert-paths
```

Provide a safe `.env.example` with placeholder values instead:

```bash
# .env.example — commit this, NOT .env
DATABASE_URL=postgres://user:password@host:5432/dbname
JWT_SECRET=replace-with-a-random-256-bit-value
```

Load secrets at runtime via environment variables only:

```js
// app.js
const jwtSecret = process.env.JWT_SECRET;
if (!jwtSecret) throw new Error('JWT_SECRET environment variable is required');
```

---

### 🟠 3. Missing Security Headers — Security Misconfiguration (A05)

**Problem:** No HTTP security headers are set. The app is vulnerable to clickjacking, MIME sniffing, and cross-site scripting via the browser's default behavior.

**Fix:** Install and use `helmet`:

```bash
npm install helmet
```

```js
const helmet = require('helmet');

// ✅ Adds X-Frame-Options, X-Content-Type-Options, Strict-Transport-Security,
//    Content-Security-Policy, and more with sane defaults
app.use(helmet());
```

Key headers `helmet` enables by default:

| Header | Protection |
|--------|-----------|
| `X-Frame-Options: DENY` | Clickjacking |
| `X-Content-Type-Options: nosniff` | MIME sniffing |
| `Strict-Transport-Security` | SSL stripping |
| `Content-Security-Policy` | XSS, data injection |

---

### 🟠 4. No Input Validation — Injection (A03)

**Problem:** There is no `express.json()` or `express.urlencoded()` middleware, so POST/PATCH bodies are ignored silently. More critically, if the app evolves to accept query parameters (e.g., `GET /users?id=...`) or body data without validation, it becomes immediately vulnerable to injection.

**Fix:** Add body parsing and always validate/sanitize inputs:

```bash
npm install zod   # or joi, express-validator
```

```js
const { z } = require('zod');

// Always add body parsers
app.use(express.json({ limit: '10kb' }));  // See also finding #8
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Define schemas for every input surface
const UserQuerySchema = z.object({
  page: z.coerce.number().int().positive().max(1000).optional(),
  limit: z.coerce.number().int().positive().max(100).optional().default(20),
});

app.get('/users', requireAuth, (req, res) => {
  const result = UserQuerySchema.safeParse(req.query);
  if (!result.success) {
    return res.status(400).json({ error: 'Invalid query parameters', details: result.error.flatten() });
  }
  const { page = 1, limit } = result.data;
  // use validated values only
  res.json([...]);
});
```

---

### 🟠 5. No Rate Limiting — Insecure Design (A04)

**Problem:** Endpoints accept unlimited requests per IP/user. This enables credential stuffing on auth endpoints, enumeration attacks, and simple DoS.

**Fix:**

```bash
npm install express-rate-limit
```

```js
const rateLimit = require('express-rate-limit');

const globalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                   // requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

// Apply globally; tighten on sensitive routes
app.use(globalLimiter);

const authLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 10 });
app.use('/login', authLimiter);
```

---

### 🟡 6. Unhandled Errors Leak Stack Traces — Security Misconfiguration (A05)

**Problem:** Without a global error handler, Express's default error handler sends full stack traces to clients in development mode and can expose file paths, library versions, and application logic in production.

**Fix:**

```js
// ✅ Place this LAST, after all routes
app.use((err, req, res, next) => {
  // Log the full error internally
  console.error({ err, path: req.path, method: req.method });

  // Never send stack traces to clients
  const status = err.status ?? err.statusCode ?? 500;
  res.status(status).json({
    error: status < 500 ? err.message : 'An unexpected error occurred',
  });
});

// Also handle 404s explicitly
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});
```

---

### 🟡 7. No CORS Policy — Security Misconfiguration (A05)

**Problem:** Without explicit CORS configuration, Express may allow or block cross-origin requests in unpredictable ways depending on the client and proxy. Allowing `*` would permit any web page to call the API on behalf of a logged-in user.

**Fix:**

```bash
npm install cors
```

```js
const cors = require('cors');

const allowedOrigins = (process.env.ALLOWED_ORIGINS ?? '').split(',').filter(Boolean);

app.use(cors({
  origin: (origin, callback) => {
    // Allow server-to-server (no origin) or whitelisted origins only
    if (!origin || allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error(`CORS policy: origin ${origin} not allowed`));
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

### 🟡 8. No Request Body Size Limit — Insecure Design (A04)

**Problem:** Without a body size cap, an attacker can send a gigabyte-sized JSON payload that exhausts memory or CPU.

**Fix:** (Already shown in finding #4, highlighted here separately)

```js
app.use(express.json({ limit: '10kb' }));
```

---

### 🟡 9. No HTTPS Enforcement — Cryptographic Failures (A02)

**Problem:** The app binds to HTTP only. Credentials, tokens, and PII travel in plaintext if TLS termination isn't enforced upstream.

**Fix:** Enforce HTTPS either at the reverse proxy (Nginx, AWS ALB — preferred) or in the app itself:

```js
// Redirect HTTP → HTTPS in production
if (process.env.NODE_ENV === 'production') {
  app.use((req, res, next) => {
    if (req.headers['x-forwarded-proto'] !== 'https') {
      return res.redirect(301, `https://${req.hostname}${req.url}`);
    }
    next();
  });
}
```

---

### 🟡 10. Missing `package.json` / Lockfile — Vulnerable Components (A06)

**Problem:** There is no `package.json` or `package-lock.json`. This means:
- Dependency versions are unknown and untracked.
- `npm install` will resolve to whatever is latest, possibly pulling in a vulnerable version of Express or a transitive dependency.
- Automated vulnerability scanners (Snyk, Dependabot) have nothing to scan.

**Fix:**

```bash
npm init -y
npm install express helmet cors express-rate-limit jsonwebtoken zod
npm audit   # check for known CVEs immediately
```

Commit both `package.json` and `package-lock.json`.

---

### 🟡 11. PII Exposed Without Need-to-Know — Broken Access Control (A01)

**Problem:** The `/users` endpoint returns email addresses to any caller. Even after authentication is added, consider whether every authenticated user needs every field.

**Fix:** Use a DTO / projection pattern — only return what the caller is authorized to see:

```js
// Define what each role can see
function toPublicUser(user) {
  return { id: user.id, name: user.name };  // no email
}
function toAdminUser(user) {
  return { id: user.id, name: user.name, email: user.email };
}

app.get('/users', requireAuth, (req, res) => {
  const isAdmin = req.user.role === 'admin';
  const users = getUsers();  // from DB
  res.json(users.map(isAdmin ? toAdminUser : toPublicUser));
});
```

---

### 🟢 12. No Logging or Audit Trail — Logging & Monitoring Failures (A09)

**Problem:** There is no request logging, no error logging, and no audit trail for sensitive operations. Without logs, breaches go undetected.

**Fix:**

```bash
npm install pino pino-http
```

```js
const pino = require('pino');
const pinoHttp = require('pino-http');

const logger = pino({ level: process.env.LOG_LEVEL ?? 'info' });

// Log every request (redact sensitive fields)
app.use(pinoHttp({
  logger,
  redact: ['req.headers.authorization', 'req.body.password'],
}));

// Audit log for sensitive actions
app.get('/users', requireAuth, (req, res) => {
  logger.info({ userId: req.user.id, action: 'list_users' }, 'User list accessed');
  res.json([...]);
});
```

